`,ColorwayTip:{title:"Ctrl + Alt + N 切换下一个配色"},compile:{label:"编译",title:"编译键位"},downloadFirmware:{label:"固件",title:"下载固件"},downloadJSON:{label:"Keymap.JSON",title:"导出 Keymap JSON 文件"},downloadKeymap:{label:"仅键位",title:"仅下载 keymap.c"},downloadSource:{label:"全部代码",title:"下载 QMK 固件代码"},downloadToolbox:{label:"获取 QMK Toolbox"},errors:{invalidQMKKeymap:"对不起，这不是一个合法的 QMK keymap 文件",kbfirmwareJSONUnsupported:"对不起，QMK Configurator 不支持 kbfirmware JSON 文件。",unknownJSON:"对不起，这似乎不是一个 QMK keymap 文件",unsupportedBrowser:"你正在使用一个不支持的浏览器。建议使用"},flashFile:{label:"自定义刷写",title:"刷写选择的固件文件到 MCU"},flashFirmware:{label:"自动刷写",title:"自动将编译好的固件刷写到 MCU"},githubKeyboardFolder:{title:"在Github上查看这个键盘"},help:{label:"开启向导"},importJSON:{title:"导入 Keymap JSON 文件"},importUrlJSON:{title:"从 URL 导入 Keymap JSON 文件"},keyboard:{label:"键盘"},keycodes:{label:"键位码"},keycodesRef:{label:"键位码参考"},keycodesTab:{ANSI:{label:"ANSI"},AppMediaMouse:{label:"应用、多媒体和鼠标"},"ISO/JIS":{label:"ISO/JIS"},KeyboardSettings:{label:"键盘设置"},Quantum:{label:"量子"},Steno:{}},keymap:{label:"键位"},keymapHelp:{label:"帮助",title:"如何使用 keymap.json？"},keymapName:{label:"键位名",placeholder:"自定义键位名"},layer:{confirm:"确认清除该层？",label:"键位层",title:"清除层"},layout:{label:"配列"},loadDefault:{label:"加载默认",title:"从 QMK 固件加载默认键位"},potato:{1:"亨利·斯伯丁于1837年在爱达荷首次种植马铃薯。",2:"法式薯条由托马斯·杰斐逊在一次白宫晚宴中带到美国。",3:"2017年，美国的土豆爱好者消费了400万吨不同形状和尺寸的薯条。",4:"土豆是一种强力的催情剂，一名爱尔兰物理学家表示。",5:"美国人每年人均食用140镑土豆。德国人每年人均食用200镑土豆。",6:"根据吉尼斯世界纪录，最大的土豆重18镑4盎司，于1795年在英格兰长成。",7:"马铃薯是世界第四大主食，排在小麦、玉米和大米之后。",8:"马铃薯在超过125个国家种植。",9:"世界每年的马铃薯产量足以覆盖一条4车道马路环绕地球6圈。",10:"中国是最大的马铃薯生产国。",11:"马铃薯是第一种在太空中种植的蔬菜。",12:"土豆是完全无麸质。",13:"印加对于时间最基本的衡量标准之一是煮土豆所需的时间。",14:"如果马铃薯暴露在光线中生长，它会变绿并且带有毒性。",15:"“制造2500磅薯片需要10,000磅土豆。”",16:"如今有4000多种不同的土豆。",17:"“马铃薯属于一个科，茄属植物或茄科。”",18:"“在阿拉斯加克朗代克淘金热期间（1897年至1898年），土豆在重量上和黄金实际上是等值的。”",19:"“沃尔特·罗利爵士于1589年在科克附近的40,000英亩土地上将土豆引入了爱尔兰。”",20:"一年四季都可以收获马铃薯，因为它们每个月都会在某个地方收获。",21:"“原产于非洲和亚洲的洋芋大小不一，从小土豆到创纪录的130磅。”",22:"8月19日和10月27日是美国的国家马铃薯日。",23:"“马铃薯还可以用来酿造酒精饮料，例如伏特加，波奇恩或阿夸维特。”",24:"“马铃薯是最环保的蔬菜之一。它们易于种植，不需要像许多其他蔬菜一样大量依赖肥料和化学添加剂。”",25:"马铃薯起源于南秘鲁地区，最早在公元前8000年至5000年之间被驯化。",26:"马铃薯的英文 potato 源自西班牙语词汇 patata。",27:"马铃薯通常由昆虫授粉，比如黄蜂。",28:"一个土豆由80%的水和20%的固体构成。"},print:{anonymous:{label:"匿名"},author:{placeholder:"你的名字（可选）",title:"作者"},back:{title:"返回"},date:{title:"日期"},keyboard:{label:"键盘"},layer:{label:"层"},layout:{label:"配列"},notes:{empty:"默认键位",placeholder:"该配置的说明",title:"说明"},print:{title:"打印"},source:{title:"源码"}},printKeymap:{label:"打印键位",title:"打印键位表"},settingsPanel:{clearLayer:{help:"更改“清除层”功能所使用的默认键码",title:"清除层默认键码"},darkmode:{help:"使用 QMK 深色主题",label:"深色模式"},fastInput:{help:"直接通过键盘输入键位",label:"快速输入",title:"ctrl + alt + f"},kcno:{},kctrns:{},language:{help:"更改用户界面语言",title:"语言"},legendType:{},legends:{},off:{label:"关闭"},on:{label:"开启"},osKeyboardLayout:{label:{keymap_german:"德语（德国和奥地利）",keymap_russian:"俄语",keymap_uk:"英语（英国）",keymap_us:"英语（美国）"}},snowflakes:{label:"开启 Snowflakes",title:"Snowflakes"},title:"配置选项",toggleTutorial:{help:"MechMerlin 的视频教程",label:"视频教程"}},testKeys:{label:"测试键盘",title:"测试键盘输入"},tester:{back:{label:"返回",title:"回到配置页面"},chatter:{detectedAlert:"探测到连击！",label:"连击阈值 (ms)"},docs:{paragraph:"注意：探测到的键位值和键位码可能会因为本地设置有所不同。文档"},keycodeStatus:{label:"键码已探测"},letters:{code:{label:"键位代码"},key:{label:"键位值"},keycode:{label:"键位码"}},page:{label:"重置"},reset:{label:"重置已测试按键",title:"开启打字机音效"},typewritericon:{label:"开启打字机音效"}},toggleTerminal:{label:"点击展开",title:"开启终端显示"}},kX={"":{},apiVersion:"API 版本",apiVersionPrefix:"API",favoriteColor:"收藏配色",favoriteKeyboard:"收藏鍵盤",hostedOn:"部署在 GitHub Pages",jobsAhead:"前往",jobsWaiting:"個任務等待中",maintain:"該專案由 QMK 開發者和貢獻者維護",ready:"就緒",searchKeycodes:"搜尋",serverIs:"服務",serverStatus:"服務狀態",settings:"設定",statsTemplate:`
